sql:
SELECT period_id, net_balance
FROM balances
ORDER BY net_balance DESC;

SELECT (b.total_income - b.total_expenses) AS net_balance
FROM balances b
WHERE b.period_id = 1;

SELECT planned_amount
FROM budget_plans
WHERE period_id = 1;

SELECT COUNT(*) AS open_periods_count
FROM financial_periods
WHERE status = 'open';

SELECT month, year
FROM financial_periods
WHERE status = 'open';

SELECT AVG(net_balance) AS average_net_balance
FROM balances
WHERE total_income > 10000;

external_knowledge:
- "fruition of financial harvests" refers to financial periods with positive net balances;
- "sealed away" is a metaphorical expression indicating that the financial periods are 'closed';
- "total positive net balances" means the sum of net balances where the balance is greater than zero.

sql:
SELECT AVG(b.net_balance) AS average_net_balance
FROM balances b
WHERE b.net_balance > (SELECT AVG(net_balance) FROM balances);

SELECT goal_name, target_amount
FROM financial_goals
ORDER BY target_amount DESC;

SELECT SUM(amount) AS total_income
FROM income_transactions
WHERE period_id = 1;
